#include <iostream>

class Tracker {
public:
    static int s_copies;

    Tracker() = default;

    Tracker(const Tracker& /*src*/) {
        ++s_copies;
    }

    static int getCopies() { return s_copies; }
};

int Tracker::s_copies = 0;

int countCopies(const Tracker& t) {
    Tracker copy{ t };          // invokes the copy constructor
    return Tracker::s_copies;
}

int main() {
    int n;
    std::cin >> n;
    Tracker base;
    for (int i = 1; i <= n; ++i) {
        int c = countCopies(base);
        std::cout << "Call " << i << ": " << c << "\n";
    }
    return 0;
}

